    "path": "package.json",
    "content": "{\n  \"name\": \"{{PROJECT_NAME}}\",\n  \"private\": true,\n  \"version\": \"0.1.0\",\n  \"description\": \"React cinema ticketing starter — full booking flow using @theatrical/sdk and @theatrical/react\",\n  \"type\": \"module\",\n  \"scripts\": {\n    \"dev\": \"vite\",\n    \"build\": \"tsc --noEmit && vite build\",\n    \"preview\": \"vite preview\"\n  },\n  \"dependencies\": {\n    \"@theatrical/react\": \"^0.1.0\",\n    \"@theatrical/sdk\": \"^0.1.0\",\n    \"react\": \"^18.2.0\",\n    \"react-dom\": \"^18.2.0\",\n    \"react-router-dom\": \"^6.22.0\",\n    \"@theatrical/events\": \"^0.1.0\",\n    \"framer-motion\": \"^11.0.0\"\n  },\n  \"devDependencies\": {\n    \"@theatrical/cli\": \"^0.1.0\",\n    \"@types/react\": \"^18.2.0\",\n    \"@types/react-dom\": \"^18.2.0\",\n    \"typescript\": \"^5.4.0\",\n    \"vite\": \"^5.2.0\",\n    \"@vitejs/plugin-react\": \"^4.2.0\"\n  }\n}\n"
